using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        // Stack (LIFO - Son giren ilk cikar)
        Stack<string> stack = new Stack<string>();
        stack.Push("Birinci");
        stack.Push("Ikinci");
        stack.Push("Ucuncu");

        Console.WriteLine("Stack icerigi (en ustten):");
        while (stack.Count > 0)
        {
            Console.WriteLine(stack.Pop());
        }

        // Queue (FIFO - Ilk giren ilk cikar)
        Queue<string> queue = new Queue<string>();
        queue.Enqueue("Musteri 1");
        queue.Enqueue("Musteri 2");
        queue.Enqueue("Musteri 3");

        Console.WriteLine("\nQueue icerigi (siradan):");
        while (queue.Count > 0)
        {
            Console.WriteLine(queue.Dequeue());
        }

        // Peek kullanimi
        Stack<int> numbers = new Stack<int>();
        numbers.Push(10);
        numbers.Push(20);
        Console.WriteLine("\nStack tepesi (Peek): " + numbers.Peek());
        Console.WriteLine("Stack eleman sayisi: " + numbers.Count);
    }
}
